+  <div id="header">
+    <h1 id="filename">New Notebook</h1>
+    <span class="status" id="status">Ready</span>
+  </div>
+  <div id="toolbar">
+    <button id="btn-run">Run Cell</button>
+    <button id="btn-run-all">Run All</button>
+    <div class="separator"></div>
+    <button id="btn-add-code">+ Code</button>
