+        document.getElementById('loading').textContent = 'Error: No PDF file specified';
+        return;
+      }
+
+      document.getElementById('filename').textContent = pdfUrl.split('/').pop();
+
+      try {
+        pdfDoc = await pdfjsLib.getDocument(pdfUrl).promise;
+        document.getElementById('total-pages').textContent = pdfDoc.numPages;
+        document.getElementById('loading').style.display = 'none';
+        updatePageInfo();
+        await renderAllPages();
+        setupThumbnails();
+      } catch (err) {
+        document.getElementById('loading').textContent = 'Error loading PDF: ' + err.message;
+      }
+    }
+
+    async function renderAllPages() {
+      const container = document.getElementById('viewer-container');
+      container.innerHTML = '';
+
+      for (let i = 1; i <= pdfDoc.numPages; i++) {
+        const page = await pdfDoc.getPage(i);
+        const viewport = page.getViewport({ scale: getScale() });
+
+        const canvas = document.createElement('canvas');
+        canvas.className = 'page-canvas';
+        canvas.dataset.page = i;
+        canvas.width = viewport.width;
+        canvas.height = viewport.height;
+
+        const ctx = canvas.getContext('2d');
+        await page.render({ canvasContext: ctx, viewport }).promise;
+
+        container.appendChild(canvas);
+      }
+    }
+
+    async function setupThumbnails() {
+      const container = document.getElementById('thumbnails');
+      container.innerHTML = '';
+
+      for (let i = 1; i <= pdfDoc.numPages; i++) {
+        const page = await pdfDoc.getPage(i);
+        const viewport = page.getViewport({ scale: 0.2 });
+
+        const canvas = document.createElement('canvas');
+        canvas.dataset.page = i;
+        canvas.width = viewport.width;
+        canvas.height = viewport.height;
+        if (i === 1) canvas.classList.add('active');
+
+        const ctx = canvas.getContext('2d');
+        await page.render({ canvasContext: ctx, viewport }).promise;
+
+        canvas.onclick = () => goToPage(i);
+        container.appendChild(canvas);
+      }
+    }
+
+    function getScale() {
+      const container = document.getElementById('viewer-container');
+      const select = document.getElementById('zoom-select');
+
+      if (select.value === 'fit-width') {
+        return (container.clientWidth - 60) / 612; // Assume letter width
+      } else if (select.value === 'fit-page') {
+        return Math.min(
+          (container.clientWidth - 60) / 612,
+          (container.clientHeight - 60) / 792
+        );
+      }
+      return parseFloat(select.value);
+    }
+
+    function goToPage(num) {
+      if (num < 1 || num > pdfDoc.numPages) return;
+      currentPage = num;
+      document.getElementById('page-input').value = num;
+      updatePageInfo();
+
+      // Scroll to page
+      const canvas = document.querySelector(`.page-canvas[data-page="${num}"]`);
+      if (canvas) {
+        canvas.scrollIntoView({ behavior: 'smooth', block: 'start' });
+      }
+
+      // Update thumbnail selection
+      document.querySelectorAll('#thumbnails canvas').forEach(c => c.classList.remove('active'));
+      const thumb = document.querySelector(`#thumbnails canvas[data-page="${num}"]`);
+      if (thumb) thumb.classList.add('active');
+    }
+
+    function updatePageInfo() {
+      document.getElementById('page-info').textContent = `Page ${currentPage} of ${pdfDoc.numPages}`;
+    }
+
+    async function changeZoom() {
+      await renderAllPages();
+    }
+
+    // Event listeners
+    document.getElementById('btn-prev').onclick = () => goToPage(currentPage - 1);
+    document.getElementById('btn-next').onclick = () => goToPage(currentPage + 1);
+    document.getElementById('page-input').onchange = (e) => goToPage(parseInt(e.target.value));
+    document.getElementById('zoom-select').onchange = changeZoom;
+    document.getElementById('btn-zoom-in').onclick = () => {
+      const select = document.getElementById('zoom-select');
+      const idx = select.selectedIndex;
+      if (idx < select.options.length - 3) {
+        select.selectedIndex = idx + 1;
+        changeZoom();
+      }
+    };
+    document.getElementById('btn-zoom-out').onclick = () => {
+      const select = document.getElementById('zoom-select');
+      if (select.selectedIndex > 0) {
+        select.selectedIndex--;
+        changeZoom();
+      }
+    };
+    document.getElementById('btn-thumbnails').onclick = () => {
+      showThumbnails = !showThumbnails;
+      document.getElementById('thumbnails').classList.toggle('visible', showThumbnails);
+      document.getElementById('viewer-container').classList.toggle('with-thumbnails', showThumbnails);
+    };
+    document.getElementById('btn-download').onclick = () => {
+      window.open(pdfUrl, '_blank');
+    };
+    document.getElementById('btn-print').onclick = () => {
+      window.print();
+    };
+
+    // Keyboard navigation
+    document.addEventListener('keydown', (e) => {
+      if (e.key === 'PageDown' || (e.key === 'ArrowDown' && e.ctrlKey)) {
+        e.preventDefault();
+        goToPage(currentPage + 1);
+      } else if (e.key === 'PageUp' || (e.key === 'ArrowUp' && e.ctrlKey)) {
+        e.preventDefault();
+        goToPage(currentPage - 1);
+      } else if (e.key === '+' || e.key === '=') {
+        document.getElementById('btn-zoom-in').click();
+      } else if (e.key === '-') {
+        document.getElementById('btn-zoom-out').click();
+      }
+    });
+
+    init();
+  </script>
+</body>
+</html>

